        public override void Validate(X509Certificate2 certificate)
        {
            if (certificate == null)
            {
                throw new ArgumentNullException("certificate");
            }

            if (DateTime.Now > certificate.NotAfter || DateTime.Now < certificate.NotBefore)
            {
                throw new SecurityTokenException("Certificate is not valid for current time period");
            }

            if (!certificate.Verify())
            {
                throw new SecurityTokenException("Certificate validation failed");
            }
        }
